// src/components/OrderForm.js
import React, { useState } from "react";
import { useOrders } from "../hooks/useOrders";

const COLORS = [
  "Onyx", "Coal Gray", "Charcoal", "Smoke", "Weathered Limestone",
  "Sandstone", "Linen", "White", "Natural Gray", "Custom"
];

const HOLE_SIZES = ["None", '1/2"', '3/4"', '1"', '1.5"', '2"', "Custom"];

const emptyForm = {
  invoice: "",
  customer: "",
  itemName: "",
  quantityUnit: "",
  quantityTotal: "",
  color: "",
  holeSize: "None",
  liner: "",
  scupper: "",
  notes: "",
};

export default function OrderForm({ onClose }) {
  const { addOrder } = useOrders();
  const [form, setForm] = useState(emptyForm);
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);

  function set(field, val) {
    setForm((f) => ({ ...f, [field]: val }));
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setSaving(true);
    try {
      await addOrder({
        invoice: form.invoice.trim(),
        customer: form.customer.trim().toUpperCase(),
        itemName: form.itemName.trim().toUpperCase(),
        quantity: `${form.quantityUnit} OF ${form.quantityTotal}`,
        color: form.color,
        holeSize: form.holeSize,
        liner: form.liner.trim(),
        scupper: form.scupper.trim(),
        notes: form.notes.trim(),
      });
      setSuccess(true);
      setForm(emptyForm);
      setTimeout(() => setSuccess(false), 2000);
    } catch (err) {
      console.error(err);
    }
    setSaving(false);
  }

  return (
    <div style={styles.overlay} onClick={onClose}>
      <div style={styles.sheet} onClick={(e) => e.stopPropagation()}>
        <div style={styles.header}>
          <h2 style={styles.title}>NEW ORDER</h2>
          <button style={styles.closeBtn} onClick={onClose}>✕</button>
        </div>

        <form onSubmit={handleSubmit} style={styles.form}>
          <Row>
            <Field label="INVOICE #" required>
              <input style={styles.input} value={form.invoice} onChange={e => set("invoice", e.target.value)} placeholder="e.g. 1042" required />
            </Field>
            <Field label="CUSTOMER" required>
              <input style={styles.input} value={form.customer} onChange={e => set("customer", e.target.value)} placeholder="Company name" required />
            </Field>
          </Row>

          <Field label="ITEM NAME" required>
            <input style={styles.input} value={form.itemName} onChange={e => set("itemName", e.target.value)} placeholder='e.g. CLASSIC MEDIUM, 60" OASIS OVAL' required />
          </Field>

          <Row>
            <Field label="UNIT #">
              <input style={{...styles.input, textAlign:"center"}} type="number" min="1" value={form.quantityUnit} onChange={e => set("quantityUnit", e.target.value)} placeholder="1" />
            </Field>
            <div style={styles.ofLabel}>OF</div>
            <Field label="TOTAL IN ORDER">
              <input style={{...styles.input, textAlign:"center"}} type="number" min="1" value={form.quantityTotal} onChange={e => set("quantityTotal", e.target.value)} placeholder="7" />
            </Field>
          </Row>

          <Row>
            <Field label="COLOR" required>
              <select style={styles.input} value={form.color} onChange={e => set("color", e.target.value)} required>
                <option value="">Select...</option>
                {COLORS.map(c => <option key={c}>{c}</option>)}
              </select>
            </Field>
            <Field label="HOLE SIZE">
              <select style={styles.input} value={form.holeSize} onChange={e => set("holeSize", e.target.value)}>
                {HOLE_SIZES.map(h => <option key={h}>{h}</option>)}
              </select>
            </Field>
          </Row>

          <Row>
            <Field label="LINER">
              <input style={styles.input} value={form.liner} onChange={e => set("liner", e.target.value)} placeholder="e.g. 14 gallon" />
            </Field>
            <Field label="SCUPPER">
              <input style={styles.input} value={form.scupper} onChange={e => set("scupper", e.target.value)} placeholder='e.g. 1.5"' />
            </Field>
          </Row>

          <Field label="NOTES">
            <textarea style={{...styles.input, minHeight:"64px", resize:"vertical"}} value={form.notes} onChange={e => set("notes", e.target.value)} placeholder="Any special instructions..." />
          </Field>

          <button style={{...styles.submitBtn, ...(success ? styles.successBtn : {})}} type="submit" disabled={saving}>
            {success ? "✓ ORDER ADDED" : saving ? "SAVING..." : "ADD TO BOARD"}
          </button>
        </form>
      </div>
    </div>
  );
}

function Row({ children }) {
  return <div style={{ display: "flex", gap: "12px", alignItems: "flex-end" }}>{children}</div>;
}

function Field({ label, children, required }) {
  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: "5px" }}>
      <label style={styles.label}>{label}{required && <span style={{color:"#e86a2f"}}> *</span>}</label>
      {children}
    </div>
  );
}

const styles = {
  overlay: {
    position: "fixed", inset: 0,
    background: "rgba(0,0,0,0.75)",
    zIndex: 100,
    display: "flex",
    alignItems: "flex-end",
  },
  sheet: {
    background: "#1a1a1a",
    borderRadius: "20px 20px 0 0",
    width: "100%",
    maxHeight: "92vh",
    overflowY: "auto",
    padding: "24px 20px 40px",
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "24px",
  },
  title: {
    color: "#fff",
    fontFamily: "'Oswald', sans-serif",
    fontSize: "20px",
    letterSpacing: "4px",
    margin: 0,
  },
  closeBtn: {
    background: "#2a2a2a",
    border: "none",
    color: "#aaa",
    borderRadius: "50%",
    width: "32px",
    height: "32px",
    fontSize: "14px",
    cursor: "pointer",
  },
  form: {
    display: "flex",
    flexDirection: "column",
    gap: "16px",
  },
  label: {
    color: "#666",
    fontSize: "10px",
    letterSpacing: "1.5px",
    fontFamily: "'Oswald', sans-serif",
  },
  input: {
    background: "#111",
    border: "1px solid #2a2a2a",
    borderRadius: "8px",
    padding: "12px 14px",
    color: "#fff",
    fontSize: "15px",
    width: "100%",
    boxSizing: "border-box",
    fontFamily: "'Inter', sans-serif",
    outline: "none",
  },
  ofLabel: {
    color: "#555",
    fontSize: "12px",
    fontFamily: "'Oswald', sans-serif",
    paddingBottom: "12px",
    letterSpacing: "1px",
  },
  submitBtn: {
    background: "#e86a2f",
    color: "#fff",
    border: "none",
    borderRadius: "10px",
    padding: "18px",
    fontSize: "14px",
    fontFamily: "'Oswald', sans-serif",
    letterSpacing: "3px",
    cursor: "pointer",
    marginTop: "8px",
    transition: "background 0.3s",
  },
  successBtn: {
    background: "#2d8a4e",
  },
};
